#include <cuda_runtime.h>
#include <math.h>

extern "C" __global__ void kernel(public_struct public_data,
                                  private_struct private_data)
{
    int point_no = private_data.point_no;
    int frame_no = public_data.frame_no;

    int ei_new;
    fp* d_in;
    int rot_row;
    int rot_col;
    int in2_rowlow;
    int in2_collow;
    int ic;
    int jc;
    int jp1;
    int ja1, ja2;
    int ip1;
    int ia1, ia2;
    int ja, jb;
    int ia, ib;
    int i;
    int j;
    int row;
    int col;
    int ori_row;
    int ori_col;
    int position;
    int pos_ori;
    int pointer;
    int ori_pointer;
    int loc_pointer;
    int cent;
    int tMask_row;
    int tMask_col;
    int largest_coordinate_current = 0;
    int largest_coordinate = 0;
    int fin_max_coo = 0;
    int largest_row;
    int largest_col;
    int offset_row;
    int offset_col;
    int ei_mod;

    fp s;
    fp sum;
    fp temp;
    fp temp2;
    fp largest_value_current = 0;
    fp largest_value = 0;
    fp fin_max_val = 0;
    fp in_final_sum;
    fp in_sqr_final_sum;
    fp mean;
    fp mean_sqr;
    fp variance;
    fp deviation;
    fp denomT;

    if(frame_no == 0) {
        pointer = point_no * public_data.frames + frame_no;
        private_data.d_tRowLoc[pointer] = private_data.d_Row[point_no];
        private_data.d_tColLoc[pointer] = private_data.d_Col[point_no];

        d_in = &private_data.d_T[private_data.in_pointer];

        for(col = 0; col < public_data.in_mod_cols; col++) {
            for(row = 0; row < public_data.in_mod_rows; row++) {
                ori_row = private_data.d_Row[point_no] - 25 + row - 1;
                ori_col = private_data.d_Col[point_no] - 25 + col - 1;
                ori_pointer = ori_col * public_data.frame_rows + ori_row;

                d_in[col * public_data.in_mod_rows + row] = public_data.d_frame[ori_pointer];
            }
        }
    }

    if(frame_no != 0) {
        in2_rowlow = private_data.d_Row[point_no] - public_data.sSize;
        in2_collow = private_data.d_Col[point_no] - public_data.sSize;

        for(col = 0; col < public_data.in2_cols; col++) {
            for(row = 0; row < public_data.in2_rows; row++) {
                ori_row = row + in2_rowlow - 1;
                ori_col = col + in2_collow - 1;
                temp = public_data.d_frame[ori_col * public_data.frame_rows + ori_row];
                private_data.d_in2[col * public_data.in2_rows + row] = temp;
                private_data.d_in2_sqr[col * public_data.in2_rows + row] = temp * temp;
            }
        }

        d_in = &private_data.d_T[private_data.in_pointer];

        for(col = 0; col < public_data.in_mod_cols; col++) {
            for(row = 0; row < public_data.in_mod_rows; row++) {
                rot_row = (public_data.in_mod_rows - 1) - row;
                rot_col = (public_data.in_mod_rows - 1) - col;
                pointer = rot_col * public_data.in_mod_rows + rot_row;

                temp = d_in[pointer];
                private_data.d_in_mod[col * public_data.in_mod_rows + row] = temp;
                private_data.d_in_sqr[pointer] = temp * temp;
            }
        }

        in_final_sum = 0;
        for(i = 0; i < public_data.in_mod_elem; i++) {
            in_final_sum += d_in[i];
        }

        in_sqr_final_sum = 0;
        for(i = 0; i < public_data.in_mod_elem; i++) {
            in_sqr_final_sum += private_data.d_in_sqr[i];
        }

        mean = in_final_sum / public_data.in_mod_elem;
        mean_sqr = mean * mean;
        variance = (in_sqr_final_sum / public_data.in_mod_elem) - mean_sqr;
        deviation = sqrtf(variance);

        denomT = sqrtf((fp)(public_data.in_mod_elem - 1)) * deviation;

        for(col = 1; col <= public_data.conv_cols; col++) {
            j = col + public_data.joffset;
            jp1 = j + 1;
            if(public_data.in2_cols < jp1) {
                ja1 = jp1 - public_data.in2_cols;
            } else {
                ja1 = 1;
            }
            if(public_data.in_mod_cols < j) {
                ja2 = public_data.in_mod_cols;
            } else {
                ja2 = j;
            }

            for(row = 1; row <= public_data.conv_rows; row++) {
                i = row + public_data.ioffset;
                ip1 = i + 1;

                if(public_data.in2_rows < ip1) {
                    ia1 = ip1 - public_data.in2_rows;
                } else {
                    ia1 = 1;
                }
                if(public_data.in_mod_rows < i) {
                    ia2 = public_data.in_mod_rows;
                } else {
                    ia2 = i;
                }

                s = 0;

                for(ja = ja1; ja <= ja2; ja++) {
                    jb = jp1 - ja;
                    for(ia = ia1; ia <= ia2; ia++) {
                        ib = ip1 - ia;
                        s += private_data.d_in_mod[public_data.in_mod_rows * (ja - 1) + ia - 1] * private_data.d_in2[public_data.in2_rows * (jb - 1) + ib - 1];
                    }
                }

                private_data.d_conv[(col - 1) * public_data.conv_rows + (row - 1)] = s;
            }
        }

        for(col = 0; col < public_data.in2_pad_cols; col++) {
            for(row = 0; row < public_data.in2_pad_rows; row++) {
                if(row > (public_data.in2_pad_add_rows - 1) &&
                   row < (public_data.in2_pad_add_rows + public_data.in2_rows) &&
                   col > (public_data.in2_pad_add_cols - 1) &&
                   col < (public_data.in2_pad_add_cols + public_data.in2_cols)) {
                    ori_row = row - public_data.in2_pad_add_rows;
                    ori_col = col - public_data.in2_pad_add_cols;
                    private_data.d_in2_pad[col * public_data.in2_pad_rows + row] = private_data.d_in2[ori_col * public_data.in2_rows + ori_row];
                } else {
                    private_data.d_in2_pad[col * public_data.in2_pad_rows + row] = 0;
                }
            }
        }

        for(ei_new = 0; ei_new < public_data.in2_pad_cols; ei_new++) {
            pos_ori = ei_new * public_data.in2_pad_rows;

            sum = 0;
            for(position = pos_ori; position < pos_ori + public_data.in2_pad_rows; position++) {
                private_data.d_in2_pad[position] += sum;
                sum = private_data.d_in2_pad[position];
            }
        }

        for(col = 0; col < public_data.in2_sub_cols; col++) {
            for(row = 0; row < public_data.in2_sub_rows; row++) {
                ori_row = row + public_data.in2_pad_cumv_sel_rowlow - 1;
                ori_col = col + public_data.in2_pad_cumv_sel_collow - 1;
                temp = private_data.d_in2_pad[ori_col * public_data.in2_pad_rows + ori_row];

                ori_row = row + public_data.in2_pad_cumv_sel2_rowlow - 1;
                ori_col = col + public_data.in2_pad_cumv_sel2_collow - 1;
                temp2 = private_data.d_in2_pad[ori_col * public_data.in2_pad_rows + ori_row];

                private_data.d_in2_sub[col * public_data.in2_sub_rows + row] = temp - temp2;
            }
        }

        for(ei_new = 0; ei_new < public_data.in2_sub_rows; ei_new++) {
            pos_ori = ei_new;

            sum = 0;
            for(position = pos_ori; position < pos_ori + public_data.in2_sub_elem; position += public_data.in2_sub_rows) {
                private_data.d_in2_sub[position] += sum;
                sum = private_data.d_in2_sub[position];
            }
        }

        for(col = 0; col < public_data.in2_sub2_sqr_cols; col++) {
            for(row = 0; row < public_data.in2_sub2_sqr_rows; row++) {
                ori_row = row + public_data.in2_sub_cumh_sel_rowlow - 1;
                ori_col = col + public_data.in2_sub_cumh_sel_collow - 1;
                temp = private_data.d_in2_sub[ori_col * public_data.in2_sub_rows + ori_row];

                ori_row = row + public_data.in2_sub_cumh_sel2_rowlow - 1;
                ori_col = col + public_data.in2_sub_cumh_sel2_collow - 1;
                temp2 = private_data.d_in2_sub[ori_col * public_data.in2_sub_rows + ori_row];

                temp2 = temp - temp2;

                private_data.d_in2_sub2_sqr[col * public_data.in2_sub2_sqr_rows + row] = temp2 * temp2;

                private_data.d_conv[col * public_data.in2_sub2_sqr_rows + row] -= temp2 * in_final_sum / public_data.in_mod_elem;
            }
        }

        for(col = 0; col < public_data.in2_pad_cols; col++) {
            for(row = 0; row < public_data.in2_pad_rows; row++) {
                if(row > (public_data.in2_pad_add_rows - 1) &&
                   row < (public_data.in2_pad_add_rows + public_data.in2_rows) &&
                   col > (public_data.in2_pad_add_cols - 1) &&
                   col < (public_data.in2_pad_add_cols + public_data.in2_cols)) {
                    ori_row = row - public_data.in2_pad_add_rows;
                    ori_col = col - public_data.in2_pad_add_cols;
                    private_data.d_in2_pad[col * public_data.in2_pad_rows + row] = private_data.d_in2_sqr[ori_col * public_data.in2_rows + ori_row];
                } else {
                    private_data.d_in2_pad[col * public_data.in2_pad_rows + row] = 0;
                }
            }
        }

        for(ei_new = 0; ei_new < public_data.in2_pad_cols; ei_new++) {
            pos_ori = ei_new * public_data.in2_pad_rows;

            sum = 0;
            for(position = pos_ori; position < pos_ori + public_data.in2_pad_rows; position++) {
                private_data.d_in2_pad[position] += sum;
                sum = private_data.d_in2_pad[position];
            }
        }

        for(col = 0; col < public_data.in2_sub_cols; col++) {
            for(row = 0; row < public_data.in2_sub_rows; row++) {
                ori_row = row + public_data.in2_pad_cumv_sel_rowlow - 1;
                ori_col = col + public_data.in2_pad_cumv_sel_collow - 1;
                temp = private_data.d_in2_pad[ori_col * public_data.in2_pad_rows + ori_row];

                ori_row = row + public_data.in2_pad_cumv_sel2_rowlow - 1;
                ori_col = col + public_data.in2_pad_cumv_sel2_collow - 1;
                temp2 = private_data.d_in2_pad[ori_col * public_data.in2_pad_rows + ori_row];

                private_data.d_in2_sub[col * public_data.in2_sub_rows + row] = temp - temp2;
            }
        }

        for(ei_new = 0; ei_new < public_data.in2_sub_rows; ei_new++) {
            pos_ori = ei_new;

            sum = 0;
            for(position = pos_ori; position < pos_ori + public_data.in2_sub_elem; position += public_data.in2_sub_rows) {
                private_data.d_in2_sub[position] += sum;
                sum = private_data.d_in2_sub[position];
            }
        }

        for(col = 0; col < public_data.conv_cols; col++) {
            for(row = 0; row < public_data.conv_rows; row++) {
                ori_row = row + public_data.in2_sub_cumh_sel_rowlow - 1;
                ori_col = col + public_data.in2_sub_cumh_sel_collow - 1;
                temp = private_data.d_in2_sub[ori_col * public_data.in2_sub_rows + ori_row];

                ori_row = row + public_data.in2_sub_cumh_sel2_rowlow - 1;
                ori_col = col + public_data.in2_sub_cumh_sel2_collow - 1;
                temp2 = private_data.d_in2_sub[ori_col * public_data.in2_sub_rows + ori_row];

                temp2 = temp - temp2;

                temp2 = temp2 - (private_data.d_in2_sub2_sqr[col * public_data.conv_rows + row] / public_data.in_mod_elem);

                if(temp2 < 0) {
                    temp2 = 0;
                }
                temp2 = sqrtf(temp2);

                temp2 = denomT * temp2;

                private_data.d_conv[col * public_data.conv_rows + row] /= temp2;
            }
        }

        cent = public_data.sSize + public_data.tSize + 1;
        pointer = frame_no - 1 + point_no * public_data.frames;
        tMask_row = cent + private_data.d_tRowLoc[pointer] - private_data.d_Row[point_no] - 1;
        tMask_col = cent + private_data.d_tColLoc[pointer] - private_data.d_Col[point_no] - 1;

        for(ei_new = 0; ei_new < public_data.tMask_elem; ei_new++) {
            private_data.d_tMask[ei_new] = 0;
        }
        private_data.d_tMask[tMask_col * public_data.tMask_rows + tMask_row] = 1;

        for(col = 1; col <= public_data.mask_conv_cols; col++) {
            j = col + public_data.mask_conv_joffset;
            jp1 = j + 1;
            if(public_data.mask_cols < jp1) {
                ja1 = jp1 - public_data.mask_cols;
            } else {
                ja1 = 1;
            }
            if(public_data.tMask_cols < j) {
                ja2 = public_data.tMask_cols;
            } else {
                ja2 = j;
            }

            for(row = 1; row <= public_data.mask_conv_rows; row++) {
                i = row + public_data.mask_conv_ioffset;
                ip1 = i + 1;

                if(public_data.mask_rows < ip1) {
                    ia1 = ip1 - public_data.mask_rows;
                } else {
                    ia1 = 1;
                }
                if(public_data.tMask_rows < i) {
                    ia2 = public_data.tMask_rows;
                } else {
                    ia2 = i;
                }

                s = 0;

                for(ja = ja1; ja <= ja2; ja++) {
                    jb = jp1 - ja;
                    for(ia = ia1; ia <= ia2; ia++) {
                        ib = ip1 - ia;
                        s += private_data.d_tMask[public_data.tMask_rows * (ja - 1) + ia - 1] * 1;
                    }
                }

                private_data.d_mask_conv[(col - 1) * public_data.conv_rows + (row - 1)] = private_data.d_conv[(col - 1) * public_data.conv_rows + (row - 1)] * s;
            }
        }

        fin_max_val = 0;
        fin_max_coo = 0;
        for(i = 0; i < public_data.mask_conv_elem; i++) {
            if(private_data.d_mask_conv[i] > fin_max_val) {
                fin_max_val = private_data.d_mask_conv[i];
                fin_max_coo = i;
            }
        }

        largest_row = (fin_max_coo + 1) % public_data.mask_conv_rows - 1;
        largest_col = (fin_max_coo + 1) / public_data.mask_conv_rows;
        if((fin_max_coo + 1) % public_data.mask_conv_rows == 0) {
            largest_row = public_data.mask_conv_rows - 1;
            largest_col = largest_col - 1;
        }

        largest_row = largest_row + 1;
        largest_col = largest_col + 1;
        offset_row = largest_row - public_data.in_mod_rows - (public_data.sSize - public_data.tSize);
        offset_col = largest_col - public_data.in_mod_cols - (public_data.sSize - public_data.tSize);
        pointer = point_no * public_data.frames + frame_no;
        private_data.d_tRowLoc[pointer] = private_data.d_Row[point_no] + offset_row;
        private_data.d_tColLoc[pointer] = private_data.d_Col[point_no] + offset_col;
    }

    if(frame_no != 0 && (frame_no % 10) == 0) {
        loc_pointer = point_no * public_data.frames + frame_no;
        private_data.d_Row[point_no] = private_data.d_tRowLoc[loc_pointer];
        private_data.d_Col[point_no] = private_data.d_tColLoc[loc_pointer];

        d_in = &private_data.d_T[private_data.in_pointer];

        for(col = 0; col < public_data.in_mod_cols; col++) {
            for(row = 0; row < public_data.in_mod_rows; row++) {
                ori_row = private_data.d_Row[point_no] - 25 + row - 1;
                ori_col = private_data.d_Col[point_no] - 25 + col - 1;
                ori_pointer = ori_col * public_data.frame_rows + ori_row;

                d_in[col * public_data.in_mod_rows + row] = public_data.alpha * d_in[col * public_data.in_mod_rows + row] + (1.0f - public_data.alpha) * public_data.d_frame[ori_pointer];
            }
        }
    }
}
